var PERFORMANCE_BUDGETS = {
  /** Color resolution per component */
  colorResolution: 0.1,
  /** Cache hit rate (0-1) */
  cacheHitRate: 0.95,
  /** Bundle size increase (KB) */
  bundleIncrease: 30
};
var PerformanceMonitor = class {
  constructor() {
    this.metrics = [];
    this.marks = /* @__PURE__ */ new Map();
    this.enabled = process.env.NODE_ENV === "development";
  }
  /**
   * Start a performance measurement
   *
   * @param name - Measurement name
   */
  mark(name) {
    if (!this.enabled) return;
    this.marks.set(name, performance.now());
  }
  /**
   * End a performance measurement
   *
   * @param name - Measurement name
   * @param metadata - Additional metadata to store
   */
  measure(name, metadata) {
    if (!this.enabled) return null;
    const startTime = this.marks.get(name);
    if (startTime === void 0) {
      console.warn(`[Performance] No mark found for "${name}"`);
      return null;
    }
    const endTime = performance.now();
    const duration = endTime - startTime;
    this.metrics.push({
      name,
      duration,
      timestamp: Date.now(),
      metadata
    });
    this.marks.delete(name);
    return duration;
  }
  /**
   * Get all metrics
   */
  getMetrics() {
    return [...this.metrics];
  }
  /**
   * Get metrics by name
   *
   * @param name - Metric name
   */
  getMetricsByName(name) {
    return this.metrics.filter((m) => m.name === name);
  }
  /**
   * Get average duration for a metric
   *
   * @param name - Metric name
   */
  getAverageDuration(name) {
    const metrics = this.getMetricsByName(name);
    if (metrics.length === 0) return 0;
    const total = metrics.reduce((sum, m) => sum + m.duration, 0);
    return total / metrics.length;
  }
  /**
   * Get p95 duration for a metric
   *
   * @param name - Metric name
   */
  getP95Duration(name) {
    const metrics = this.getMetricsByName(name);
    if (metrics.length === 0) return 0;
    const sorted = metrics.map((m) => m.duration).sort((a, b) => a - b);
    const index = Math.ceil(sorted.length * 0.95) - 1;
    return sorted[index];
  }
  /**
   * Clear all metrics
   */
  clear() {
    this.metrics = [];
    this.marks.clear();
  }
  /**
   * Log performance summary to console
   */
  logSummary() {
    if (!this.enabled || this.metrics.length === 0) return;
    const metricNames = [...new Set(this.metrics.map((m) => m.name))];
    console.group("[Performance] Color Solver Summary");
    for (const name of metricNames) {
      const avg = this.getAverageDuration(name);
      const p95 = this.getP95Duration(name);
      const count = this.getMetricsByName(name).length;
      console.log(`${name}:`);
      console.log(`  Count: ${count}`);
      console.log(`  Avg: ${avg.toFixed(3)}ms`);
      console.log(`  P95: ${p95.toFixed(3)}ms`);
      const budget = PERFORMANCE_BUDGETS.colorResolution;
      if (avg > budget) {
        console.warn(`  \u26A0\uFE0F Average exceeds budget (${budget}ms)`);
      }
    }
    console.groupEnd();
  }
  /**
   * Check if enabled
   */
  isEnabled() {
    return this.enabled;
  }
};
var performanceMonitor = new PerformanceMonitor();
function measurePerformance(name, fn, metadata) {
  performanceMonitor.mark(name);
  const result = fn();
  performanceMonitor.measure(name, metadata);
  return result;
}
if (process.env.NODE_ENV === "development") {
  setInterval(() => {
    performanceMonitor.logSummary();
  }, 1e4);
}
function exportMetrics() {
  const metrics = performanceMonitor.getMetrics();
  return JSON.stringify(metrics, null, 2);
}
function checkBudget(metricName, budget) {
  const avg = performanceMonitor.getAverageDuration(metricName);
  return avg <= budget;
}

